INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 106001, 7001, 0.0, -363.0, 1, "キャル", "2015/12/17 15:00:00", 7, "たまには\n協力するのもいいんじゃない？\nあたしも手を貸してあげる", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 105901, 7002, 0.0, -363.0, 1, "コッコロ", "2015/12/17 15:00:00", 7, "多くの方と協力して\n戦えるようです\n主さまなら、さぞ\nご活躍なさることでしょう", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 105801, 7003, 0.0, -363.0, 1, "ペコリーヌ", "2015/12/17 15:00:00", 7, "たくさんの人と一緒に\n協力バトルです！\nがんばりましょう☆", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 105801, 10001, 0.0, -363.0, 1, "ペコリーヌ", "2015/12/17 15:00:00", 10, "ジュエルを食べ物…\nいえ、貴重品と交換できます！", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 106001, 10002, 0.0, -363.0, 1, "キャル", "2015/12/17 15:00:00", 10, "ジュエルはよく考えて\n使うことね\n無駄遣い厳禁！", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 105901, 10003, 0.0, -363.0, 1, "コッコロ", "2015/12/17 15:00:00", 10, "主さまのジュエルで\n貴重な品々を購入できます\nですが、無駄遣いは\n『めっ』でございますよ", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 106401, 10004, 0.0, -363.0, 1, "シェフィ", "2015/12/17 15:00:00", 10, "ジュエルがあれば\n貴重品と交換できるみたい\n大事に使いましょうね", 0, "2030/12/17 14:59:59", 2104010, 2);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 105801, 12001, 0.0, -416.5, 1, "ペコリーヌ", "2015/12/17 15:00:00", 12, "特定の条件を達成すると\n報酬がもらえますよ！\nがんばりましょう♪　", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 106001, 13001, 0.0, -363.0, 1, "キャル", "2015/12/17 15:00:00", 13, "思い出が詰まってるって\nいろいろあったけど\n振り返るのもいいんじゃない？", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 105901, 13002, 0.0, -363.0, 1, "コッコロ", "2015/12/17 15:00:00", 13, "主さまとの楽しい日々…\nこちらで何度でも\n思い返しましょう♪", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 106401, 13003, 0.0, -363.0, 1, "シェフィ", "2015/12/17 15:00:00", 13, "みんなとの大切な思い出が\nたくさん詰まってるのね\n一緒に振り返って、\n心に刻みたいわ", 0, "2030/12/17 14:59:59", 2104010, 2);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 105801, 13004, 0.0, -363.0, 1, "ペコリーヌ", "2015/12/17 15:00:00", 13, "女の子との思い出が\nたくさん見られますよ！\nヒューヒュー♪\nモテモテですねー☆", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 105901, 14001, 0.0, -363.0, 1, "コッコロ", "2015/12/17 15:00:00", 14, "育成に必要なアイテムが\n獲得できるクエストです\nわたくし、主さまのために、\n強くなりますよ", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 106401, 14002, 0.0, -363.0, 1, "シェフィ", "2015/12/17 15:00:00", 14, "このクエストを攻略すると、\nアイテムが手に入るらしいわ。\nもっと強くなるために、\n一生懸命がんばるわね！", 0, "2030/12/17 14:59:59", 2104010, 2);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 105801, 14003, 0.0, -363.0, 1, "ペコリーヌ", "2015/12/17 15:00:00", 14, "このクエストを攻略すれば、\nアイテムがもらえますよ\nたくさん集めて、どんどん\n強くなっちゃいましょう！", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 106001, 14004, 0.0, -363.0, 1, "キャル", "2015/12/17 15:00:00", 14, "クエストを攻略すると、\nアイテムが手に入るんだって\nもらえるものは、\nもらっておきましょ！", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 105901, 15001, 0.0, -470.0, 1, "コッコロ", "2015/12/17 15:00:00", 15, "主さま、旅の準備を整えて\nより充実した冒険をいたし\nましょう", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 106401, 16001, 0.0, -363.0, 1, "シェフィ", "2015/12/17 15:00:00", 16, "ねぇ…クランに加入してみない？\n一人も楽しいけど、みんなと\n一緒も賑やかでいいと思うの", 0, "2030/12/17 14:59:59", 2104010, 2);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 105801, 16002, 0.0, -363.0, 1, "ペコリーヌ", "2015/12/17 15:00:00", 16, "クランに加入してみませんか？\nみんなといっしょに冒険した方が、\n楽しいですよ！", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 106001, 16003, 0.0, -363.0, 1, "キャル", "2015/12/17 15:00:00", 16, "クランに入れるらしいわよ\nせっかくだから入ってみたら？\nけっこう楽しいみたいよ♪", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 105901, 16004, 0.0, -363.0, 1, "コッコロ", "2015/12/17 15:00:00", 16, "こちらでクランに加入できます\n素敵なクランがたくさんあって、\n目移りしてしまいますね", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 105901, 17002, 0.0, -363.0, 1, "コッコロ", "2015/12/17 15:00:00", 17, " こちらではクランバトルに\n 参加された仲間のみなさんの\n 活躍を振り返ることができます", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 106001, 17004, 0.0, -363.0, 1, "キャル", "2015/12/17 15:00:00", 25, "模擬戦の戦績もアンタが\n気に入ったものがあれば\n記録しておけるのね", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 105901, 17005, 0.0, -363.0, 1, "コッコロ", "2015/12/17 15:00:00", 25, "主さま、今回のクランバトルでの\nご活躍が記録されています\nバトルの参考にいたしましょう", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 106401, 17006, 0.0, -363.0, 1, "シェフィ", "2015/12/17 15:00:00", 25, "今回のクランバトルの調子は\nどうかしら？\n戦績を見れば、次のバトルに\n活かせるかもしれないわ", 0, "2030/12/17 14:59:59", 2104010, 2);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 105801, 17007, 0.0, -363.0, 1, "ペコリーヌ", "2015/12/17 15:00:00", 25, "今回のクランバトルでの戦績を\nおさらいできますよ！\n私にも見せてください☆", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 190801, 18001, 0.0, -363.0, 1, "カリン", "2015/12/17 15:00:00", 18, "ようこそ！\nこちらでは、\nギルドハウスで流れる音楽の\n変更や購入が出来ますよ", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 190801, 18002, 0.0, -363.0, 2, "カリン", "2015/12/17 15:00:00", 18, "ＢＧＭの変更や購入は、こちらから\nできますよ\n素敵な音楽を、たくさんご用意\nいたしました！", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 190801, 19001, 0.0, -470.0, 3, "カリン", "2015/12/17 15:00:00", 19, "ギルドハウスの\nＢＧＭを変更できますよ\nあなたの好きな曲、\n私にも聴かせてくださいね", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 190801, 19002, 0.0, -470.0, 4, "カリン", "2015/12/17 15:00:00", 19, "こちらでは、ＢＧＭの変更が\nできますよ\nどんな曲に変更しますか？\nふふふ、私も楽しみです♪", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 190801, 20001, 0.0, -470.0, 5, "カリン", "2015/12/17 15:00:00", 20, "こちらでは、ＢＧＭを購入\nすることができますよ\n試聴することもできるので、\nじっくり選んでくださいね", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 190801, 20002, 0.0, -470.0, 6, "カリン", "2015/12/17 15:00:00", 20, "いらっしゃいませ！\nＢＧＭの購入はこちらです\n素敵な曲がたくさんあって、\n目移りしちゃいますね", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 106001, 21001, 0.0, -363.0, 1, "キャル", "2015/12/17 15:00:00", 21, "ここで手に入れたアイテムで\n専用装備を作成できるみたいね\nアイテムが集まったら\nさっそく作ってみましょ！", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 105901, 21002, 0.0, -363.0, 1, "コッコロ", "2015/12/17 15:00:00", 21, "攻略すると珍しいアイテムが\n手に入りますよ\nこのアイテムで専用装備を\n作成できるようです", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 106401, 21003, 0.0, -363.0, 1, "シェフィ", "2015/12/17 15:00:00", 21, "専用装備が欲しいなら\nこのクエストに挑戦するといいわ\n集めた素材でもっともっと\n強くなりましょう", 0, "2030/12/17 14:59:59", 2104010, 2);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 105801, 21004, 0.0, -363.0, 1, "ペコリーヌ", "2015/12/17 15:00:00", 21, "専用装備の作成に必要な\nアイテムを獲得できますよ\nたくさん集めてどんどん\n強くなりましょう！", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 190801, 22001, 0.0, -430.0, 1, "カリン", "2015/12/17 15:00:00", 22, "投票はこちらです\nあなたが応援したい女の子に\n思いを込めた一票を\nお願いします！", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 190801, 22002, 0.0, -430.0, 2, "カリン", "2015/12/17 15:00:00", 22, "ようこそ！\nあなたが思いを寄せるのは\nどの女の子ですか？\n応援してあげてくださいね！", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 190801, 23001, 0.0, -430.0, 3, "カリン", "2015/12/17 15:00:00", 23, "たくさんの投票、\nありがとうございました\n結果発表を楽しみに\n待っていてくださいね！", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 190801, 23002, 0.0, -430.0, 4, "カリン", "2015/12/17 15:00:00", 23, "ただ今、人気投票の\n集計中です\n結果が出るまでもう少しだけ\nお待ちくださいね", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2, 4.08, 109001, 24001, 8.0, -385.0, 1, "エリコ（バレンタイン）", "2019/01/31 12:00:00", 24, "あなた様が手伝ってくださった\nチョコレートケーキ\n美味しくないはずがありませんわ", 10011, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2, 5.0, 109001, 24002, 8.0, -385.0, 2, "エリコ（バレンタイン）", "2019/01/31 12:00:00", 24, "このような失敗、あなた様が\nするはずありません\nもう一度挑戦してみましょう", 10011, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2, 10.11, 109001, 24003, 8.0, -385.0, 3, "エリコ（バレンタイン）", "2019/01/31 12:00:00", 24, "あなた様のために\n作っているケーキを\nあなた様に手伝っていただく……\nことになるなんて……クスクス", 10011, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2, 4.0, 109001, 24004, 8.0, -385.0, 4, "エリコ（バレンタイン）", "2019/01/31 12:00:00", 24, "あまり気に病む必要はありませんわ\nこれからは私がたっぷりと\n時間をかけて教えて差し上げますから", 10011, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2, 6.0, 109001, 24005, 8.0, -385.0, 5, "エリコ（バレンタイン）", "2019/01/31 12:00:00", 24, "今回は調子が悪かった……のですか？\nあなた様が手伝ってくれたものなら\nわたしはどんなものでも……クスクス", 10011, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 109002, 24006, 0.0, 0.0, 6, "エリコ（バレンタイン）", "2019/01/31 12:00:00", 24, "あなた様が手がけた\nチョコレートケーキは\n私にとっての宝物……\n侮辱する者は生かしておきませんわ", 10011, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 109002, 24007, 0.0, 0.0, 7, "エリコ（バレンタイン）", "2019/01/31 12:00:00", 24, "とても素晴らしい出来栄えですわ！\nあなた様にふさわしい\nチョコレートケーキができました", 10011, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 109002, 24008, 0.0, 0.0, 8, "エリコ（バレンタイン）", "2019/01/31 12:00:00", 24, "私を手伝ってくれたあなた様は\nすでに私の虜……\n甘い世界に誘って差し上げますわ", 10011, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 109002, 24009, 0.0, 0.0, 9, "エリコ（バレンタイン）", "2019/01/31 12:00:00", 24, "あなた様の愛情\nしかと受け止めました\nこれが……私たちの初めての\n共同作業ですわね……クスクス", 10011, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 109002, 24010, 0.0, 0.0, 10, "エリコ（バレンタイン）", "2019/01/31 12:00:00", 24, "これは世界一の\nチョコレートケーキですわ\nだって、あなた様が腕によりをかけて\n作ってくださったんですもの", 10011, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2, 2.12, 109101, 24011, 8.0, -385.0, 1, "シズル（バレンタイン）", "2019/01/31 12:00:00", 24, "上手にできなくて残念だった？\nでも、弟くんの気持ちが嬉しいな\nいつだってお姉ちゃんは\nそばにいるからね♪", 10011, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2, 4.19, 109101, 24012, 8.0, -385.0, 2, "シズル（バレンタイン）", "2019/01/31 12:00:00", 24, "うーん、弟くんには珍しく\n緊張しちゃったのかな？\nもう一度チャレンジしてみる？", 10011, "2030/12/17 14:59:59", 0, 5);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (4, 2.3, 109101, 24013, 8.0, -385.0, 3, "シズル（バレンタイン）", "2019/01/31 12:00:00", 24, "お姉ちゃんのお手伝い、\nよくできました！\nあー、\nまだつまみ食いしちゃダメだぞ！", 10011, "2030/12/17 14:59:59", 0, 2);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 109102, 24014, 0.0, 0.0, 4, "シズル（バレンタイン）", "2019/01/31 12:00:00", 24, "見てみて！\nスポンジに綺麗な焼き目がついてるよ\nさっすが弟くんだね！", 10011, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2, 5.23, 109101, 24015, 8.0, -385.0, 5, "シズル（バレンタイン）", "2019/01/31 12:00:00", 24, "まぁまぁ、落ち込まないで\n見た目は……個性的だけど、\n味は絶対美味しいはずだから！", 10011, "2030/12/17 14:59:59", 0, 5);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 109102, 24016, 0.0, 0.0, 6, "シズル（バレンタイン）", "2019/01/31 12:00:00", 24, "弟くんみたいな\n可愛いケーキができたよ！\n早く食べてみたいでしょ♪", 10011, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2, 5.01, 109101, 24017, 8.0, -385.0, 7, "シズル（バレンタイン）", "2019/01/31 12:00:00", 24, "あれれ？　弟くん、指に\nチョコレートがくっついてるよ？\nお姉ちゃんが舐めてあげるね、\nはぁむ！", 10011, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 109102, 24018, 0.0, 0.0, 8, "シズル（バレンタイン）", "2019/01/31 12:00:00", 24, "なかなか上手にできたんじゃない？\nでも弟くんはまだまだできる子！\nお姉ちゃん、信じてるからね", 10011, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 109102, 24019, 0.0, 0.0, 9, "シズル（バレンタイン）", "2019/01/31 12:00:00", 24, "わぁ～、\nとっても美味しそうにできたね！\n弟くん手慣れてたから\nお姉ちゃん安心して任せられちゃった！", 10011, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 109102, 24020, 0.0, 0.0, 10, "シズル（バレンタイン）", "2019/01/31 12:00:00", 24, "や～ん、弟くんが手伝ってくれた\nチョコレートケーキ！\nすっごく美味しそうにできたね♪", 10011, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 106401, 26001, 0.0, -363.0, 1, "シェフィ", "2015/12/17 15:00:00", 26, "ここから先は神聖な場所みたい\nどんなお宝が眠っているのか、\n今から探索するのが楽しみね♪", 0, "2030/12/17 14:59:59", 2104010, 2);
