INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 105901, 26004, 0.0, -363.0, 1, "コッコロ", "2015/12/17 15:00:00", 26, "ここから先は神聖な場所\nでございます。\n気を引き締めてお宝の\n調査探索に参りましょう", 0, "2030/12/17 14:59:59", 0, 1);
