INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 123001, 43005, 0.0, -416.5, 2, "アメス", "2015/12/17 15:00:00", 44, "ぼんやりしてる場合じゃないわ。\n早くミッションをクリアして\n報酬を受け取ってきなさい！", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2, 5.79, 123001, 43006, 0.0, -416.5, 3, "アメス", "2015/12/17 15:00:00", 45, "ちょっとあんた、報酬が\n受け取れるじゃない！\n忘れずにチェックなさい。\nアメス様との約束よ？", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 0.0, 123001, 46001, 0.0, -371.5, 1, "アメス", "2015/12/17 15:00:00", 46, "はい、お疲れさま。\nここではマスタリーチケットを\n使って、マスタリー強化素材を\n手に入れることができるわよ。", 0, "2030/12/17 14:59:59", 0, 1);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2, 0.0, 104901, 47001, 0.0, -416.5, 1, "シズル", "2015/12/17 15:00:00", 47, "呼ばれて飛び出てお姉ちゃんだよ♪\nたとえ火の中、水の中、迷宮の中っ\nこのダンジョンを踏破できるよう\n弟くんを応援してあげるからねっ♪", 0, "2030/12/17 14:59:59", 0, 2);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2, 9.32, 101101, 47002, 0.0, -416.5, 1, "リノ", "2015/12/17 15:00:00", 47, "ほんとーに不思議な場所ですね～\nお兄ちゃんが冒険を頑張れるよう\nおまじないをかけてあげますねっ\nフレーフレー、お・兄・ちゃんっ♪", 0, "2030/12/17 14:59:59", 0, 1);
